def get_even_numbers(numbers):
    result = []
    for n in numbers:
        if n % 2 == 0:
            result.append(n)
    return result

def process_data(data, options):
    result = []
    for item in data:
        if options.get('upper'):
            result.append(item.upper())
        else:
            result.append(item.lower())
    return result

